function run(repos) {
    try {
        var parsed = typeof repos === 'string' ? JSON.parse(repos) : repos;

        var items = parsed.map(function(repo) {
            return {
                type: "image/jpeg",
                uri: repo.avatarUrl,
                title: repo.fullName,
                text: repo.description || "Sin descripción disponible"
            };
        });

        var carousel = {
            itemType: "application/vnd.lime.media-link+json",
            items: items
        };

        return JSON.stringify(carousel);
    } catch (e) {
        return JSON.stringify({ error: e.message });
    }
}
